protected function excludeIgnoredProp(mixed $prop, string $path): bool
    {
        if ($prop instanceof Deferrable && $prop->shouldDefer()
            && ! $this->wasAlreadyLoadedByClient($prop, $path)) {
            $this->collectDeferredPropMetadata($path, $prop);
        }

        if ($prop instanceof Mergeable && $prop->shouldMerge()) {
            $this->collectMergeableMetadata($path, $prop);
        }

        if ($prop instanceof Onceable && $prop->shouldResolveOnce()) {
            $this->collectOnceMetadata($path, $prop);
        }

        return true;
    }

public static function modelsFor(array $targets)
    {
        $models = [];

        foreach ($targets as $target) {
            $models[] = collect((new ReflectionClass($target))->getProperties())
                ->map(function ($property) use ($target) {
                    if (PHP_VERSION_ID < 80500) {
                        $property->setAccessible(true);
                    }

                    $value = static::getValue($property, $target);

                    if ($value instanceof Model) {
                        return [$value];
                    } elseif ($value instanceof EloquentCollection) {
                        return $value->all();
                    }
                })
                ->collapse()
                ->filter()
                ->all();
        }

        return collect($models)->collapse()->unique();
    }

public function calculate($queue = null)
    {
        $queues = $this->queueNames(
            $supervisors = collect($this->supervisors->all()), $queue
        );

        return $queues->mapWithKeys(function ($queue) use ($supervisors) {
            $totalProcesses = $this->totalProcessesFor($supervisors, $queue);

            [$connection, $queueName] = explode(':', $queue, 2);

            return [$queue => $this->calculateTimeToClear($connection, $queueName, $totalProcesses)];
        })
            ->sort()
            ->reverse()
            ->all();
    }

protected function getPsrRequestViaBearerToken(): ?ServerRequestInterface
    {
        // First, we will convert the Symfony request to a PSR-7 implementation which will
        // be compatible with the base OAuth2 library. The Symfony bridge can perform a
        // conversion for us to a new PSR-7 implementation from this Symfony request.
        $psr = (new PsrHttpFactory)->createRequest($this->request);

        try {
            return $this->server->validateAuthenticatedRequest($psr);
        } catch (OAuthServerException $e) {
            $this->request->headers->set('Authorization', '', true);

            report($e);

            return null;
        }
    }

protected function makeAuthorizationServer(?ResponseTypeInterface $responseType = null): AuthorizationServer
    {
        return tap(new AuthorizationServer(
            $this->app->make(Bridge\ClientRepository::class),
            $this->app->make(Bridge\AccessTokenRepository::class),
            $this->app->make(Bridge\ScopeRepository::class),
            $this->makeCryptKey('private'),
            Passport::tokenEncryptionKey($this->app->make('encrypter')),
            $responseType ?? Passport::$authorizationServerResponseType
        ), function (AuthorizationServer $server): void {
            $server->setDefaultScope(Passport::$defaultScope);
            $server->revokeRefreshTokens(Passport::$revokeRefreshTokenAfterUse);
        });
    }

protected function isValidAccessToken($accessToken): bool
    {
        if (! $accessToken) {
            return false;
        }

        $isValid =
            (! $this->expiration || $accessToken->created_at->gt(now()->subMinutes($this->expiration)))
            && (! $accessToken->expires_at || ! $accessToken->expires_at->isPast())
            && $this->hasValidProvider($accessToken->tokenable);

        if (is_callable(Sanctum::$accessTokenAuthenticationCallback)) {
            $isValid = (bool) (Sanctum::$accessTokenAuthenticationCallback)($accessToken, $isValid);
        }

        return $isValid;
    }

protected function frontendMiddleware()
    {
        $middleware = array_values(array_filter(array_unique([
            config('sanctum.middleware.encrypt_cookies', \Illuminate\Cookie\Middleware\EncryptCookies::class),
            \Illuminate\Cookie\Middleware\AddQueuedCookiesToResponse::class,
            \Illuminate\Session\Middleware\StartSession::class,
            config('sanctum.middleware.validate_csrf_token', config('sanctum.middleware.verify_csrf_token', \Illuminate\Foundation\Http\Middleware\VerifyCsrfToken::class)),
            config('sanctum.middleware.authenticate_session'),
        ])));

        array_unshift($middleware, function ($request, $next) {
            $request->attributes->set('sanctum', true);

            return $next($request);
        });

        return $middleware;
    }

public function handle()
    {
        $model = Sanctum::$personalAccessTokenModel;

        $hours = $this->option('hours');

        $this->components->task(
            'Pruning tokens with expired expires_at timestamps',
            fn () => $model::where('expires_at', '<', now()->subHours($hours))->delete()
        );

        if ($expiration = config('sanctum.expiration')) {
            $this->components->task(
                'Pruning tokens with expired expiration value based on configuration file',
                fn () => $model::where('created_at', '<', now()->subMinutes($expiration + ($hours * 60)))->delete()
            );
        } else {
            $this->components->warn('Expiration value not specified in configuration file.');
        }

        $this->components->info("Tokens expired for more than [$hours hours] pruned successfully.");

        return 0;
    }

public function registerSearchableMacros()
    {
        $self = $this;

        BaseCollection::macro('searchable', function () use ($self) {
            $self->queueMakeSearchable($this);
        });

        BaseCollection::macro('unsearchable', function () use ($self) {
            $self->queueRemoveFromSearch($this);
        });

        BaseCollection::macro('searchableSync', function () use ($self) {
            $self->syncMakeSearchable($this);
        });

        BaseCollection::macro('unsearchableSync', function () use ($self) {
            $self->syncRemoveFromSearch($this);
        });
    }

public function on(string $name, callable $callback): callable
    {
        $this->listeners[$name][] = $callback;

        return fn() => $this->off($name, $callback);
    }

    public function before(string $name, callable $callback): callable
    {
        $this->listenersBefore[$name][] = $callback;

        return fn() => $this->off($name, $callback);
    }

    public function after(string $name, callable $callback): callable
    {
        $this->listenersAfter[$name][] = $callback;

        return fn() => $this->off($name, $callback);
    }

protected static function enforceRateLimit()
    {
        if (app()->runningUnitTests() && ! static::$rateLimitingEnabledForTesting) return;

        $request = request();

        // Only check the rate limit once per request (not once per component)
        if ($request->attributes->get('livewire_rate_limit_checked')) {
            return;
        }

        $key = static::rateLimitKey();

        if (RateLimiter::tooManyAttempts($key, static::$maxFailures)) {
            $seconds = RateLimiter::availableIn($key);

            throw new TooManyRequestsHttpException(
                $seconds,
                'Too many invalid Livewire requests. Please try again later.'
            );
        }

        $request->attributes->set('livewire_rate_limit_checked', true);
    }

public function handle(): int
    {
        try {
            $this->configureHasClusterClassesOutsideDirectories();
            $this->configureFqnEnd();
            $this->configurePanel(question: 'Which panel would you like to create this cluster in?');
            $this->configureClustersLocation();

            $this->configureFqn();

            $this->createClass();
        } catch (FailureCommandOutput) {
            return static::FAILURE;
        }

        $this->components->info("Filament cluster [{$this->fqn}] created successfully.");

        if (empty($this->panel->getClusterNamespaces())) {
            $this->components->info('Make sure to register the cluster with [clusters()] or discover it with [discoverClusters()] in the panel service provider.');
        }

        return static::SUCCESS;
    }

public function sendNow($notifiables, $notification, ?array $channels = null)
    {
        $notifiables = $this->formatNotifiables($notifiables);

        $original = clone $notification;

        foreach ($notifiables as $notifiable) {
            if (empty($viaChannels = $channels ?: $original->via($notifiable))) {
                continue;
            }

            $this->withLocale($this->preferredLocale($notifiable, $original), function () use ($viaChannels, $notifiable, $original) {
                $notificationId = (string) Str::uuid();

                foreach ((array) $viaChannels as $channel) {
                    if (! ($notifiable instanceof AnonymousNotifiable && $channel === 'database')) {
                        $this->sendToNotifiable($notifiable, $notificationId, clone $original, $channel);
                    }
                }
            });
        }
    }

protected function regenerateIslandCacheFiles()
    {
        // Get the view - SFCs use view(), regular components use render()...
        if (method_exists($this, 'view')) {
            $viewOrString = $this->view();
        } elseif (method_exists($this, 'render')) {
            $viewOrString = $this->render();
        } else {
            return;
        }

        if (! $viewOrString) return;

        $view = Utils::generateBladeView($viewOrString);
        $viewPath = $view->getPath();

        // Force Blade to recompile the view, which triggers island cache file
        // regeneration via the prepareStringsForCompilationUsing hook...
        $compiledPath = app('blade.compiler')->getCompiledPath($viewPath);

        if (file_exists($compiledPath)) {
            @unlink($compiledPath);
        }

        app('blade.compiler')->compile($viewPath);
    }

public function test_reactive_prop_value_is_available_during_boot_hydrate_and_booted_hooks()
    {
        Livewire::component('child-with-lifecycle-hooks', ChildWithLifecycleHooks::class);

        $child = Livewire::test(ChildWithLifecycleHooks::class, ['count' => 0]);
        $this->assertEquals(0, $child->get('count'));

        // Simulate parent passing count=5 on next request
        SupportReactiveProps::$pendingChildParams[$child->id()] = ['count' => 5];
        $child->call('$refresh');

        $this->assertEquals(5, $child->get('count'));
        $this->assertEquals(5, $child->get('bootValue'), 'boot() should see the new reactive prop value');
        $this->assertEquals(5, $child->get('hydrateValue'), 'hydrate() should see the new reactive prop value');
        $this->assertEquals(5, $child->get('bootedValue'), 'booted() should see the new reactive prop value');
    }

public function getSchemaState(): mixed
    {
        $schemaComponent = $this->getSchemaComponent();
        $arguments = $this->getArguments();

        if (
            $schemaComponent instanceof HasExtraItemActions &&
            filled($itemKey = $arguments['item'] ?? null)
        ) {
            return $schemaComponent->getItemState($itemKey);
        }

        $schemaContainer = $this->getSchemaContainer();

        while ($schemaContainer) {
            if (filled($schemaContainer->getStatePath(isAbsolute: false))) {
                return $schemaContainer->getStateSnapshot();
            }

            $parentComponent = $schemaContainer->getParentComponent();

            if (! $parentComponent) {
                return $schemaContainer->getStateSnapshot();
            }

            $schemaContainer = $parentComponent->getContainer();
        }

        return null;
    }

